namespace py = pybind11;

#include <gnuradio/Aegir/AegirSDR.h>
// pydoc.h is automatically generated in the build directory
#include <AegirSDR_pydoc.h>

void bind_AegirSDR(py::module& m)
{

    using AegirSDR    = gr::Aegir::AegirSDR;


    py::class_<AegirSDR, gr::sync_block, gr::block, gr::basic_block,
        std::shared_ptr<AegirSDR>>(m, "AegirSDR", D(AegirSDR))

        .def(py::init(&AegirSDR::make),
             py::arg("address"),
             py::arg("ctrl_address"),
             py::arg("nchannels"),
             py::arg("blocksize"),
             py::arg("timeout_ms") = 100,
             D(AegirSDR,make)
        )
        



        ;




}








